+
+bool cli_option_exist(char ** begin, char ** end, const char * option)
+{
+  // return std::find(begin, end, option) != end;
+  for (size_t i = 0; i < (size_t)(end - begin); ++i) {
+    if (strcmp(begin[i], option) == 0) {
+      return true;
+    }
+  }
+  return false;
+}
+
+char * cli_get_option(char ** begin, char ** end, const char * option)
+{
+  size_t idx = 0;
+  size_t end_idx = end - begin;
+  for (; idx < end_idx; ++idx) {
+    if (strncmp(begin[idx], option, strlen(option)) == 0) {
+      break;
+    }
+  }
+
+  if (idx == end_idx) {
+    return NULL;
+  }
+
+  if (begin[idx] != NULL && begin[++idx] != NULL) {
+    return begin[idx];
+  }
+
+  return NULL;
+}

