+bool
+utilities_is_directory(const char * abs_path)
+{
+  struct stat buf;
+  if (stat(abs_path, &buf) < 0) {
+    return false;
+  }
+#ifdef WIN32
+  return (buf.st_mode & S_IFDIR) == S_IFDIR;
+#else
+  return S_ISDIR(buf.st_mode);
+#endif
+}
+
+bool
+utilities_is_file(const char * abs_path)
+{
+  struct stat buf;
+  if (stat(abs_path, &buf) < 0) {
+    return false;
+  }
+#ifdef WIN32
+  return (buf.st_mode & S_IFREG) == S_IFREG;
+#else
+  return S_ISREG(buf.st_mode);
+#endif
+}
+
+bool
+utilities_exists(const char * abs_path)
+{
+  struct stat buf;
+  if (stat(abs_path, &buf) < 0) {
+    return false;
+  }
+  return true;
+}
+
+bool
+utilities_is_readable(const char * abs_path)
+{
+  struct stat buf;
+  if (!utilities_exists(abs_path)) {
+    return false;
+  }
+  stat(abs_path, &buf);
+#ifdef WIN32
+  if (!(buf.st_mode & _S_IREAD)) {
+#else
+  if (!(buf.st_mode & S_IRUSR)) {
+#endif
+    return false;
+  }
+  return true;
+}
+
+bool
+utilities_is_writable(const char * abs_path)
+{
+  struct stat buf;
+  if (!utilities_exists(abs_path)) {
+    return false;
+  }
+  stat(abs_path, &buf);
+#ifdef WIN32
+  if (!(buf.st_mode & _S_IWRITE)) {
+#else
+  if (!(buf.st_mode & S_IWUSR)) {
+#endif
+    return false;
+  }
+  return true;
+}
+
+bool
+utilities_is_readable_and_writable(const char * abs_path)
